/**
 * test/util/epsilon.js - Provides comparison functions that compensate for the
 * precision limitations of floating numbers.
 */
var assert = require("assert");
var EPSILON = 0.000001;

const epsilon = {

    // Export constant too
    EPSILON,

    /**
     * equal - Compare two numbers and check if they are equal within a distance of epsilon
     *
     * @param  {number} a Value to compare against b
     * @param  {number} b Value to compare against a
     *
     * Throws an error if they are not equal
     */
    equal: function(a, b, errorMessage){
        assert(a > (b - EPSILON) && a < (b + EPSILON), errorMessage);
    },

    /**
     * deepEqual - Tests for deep equality, but uses epsilon.equal to compare values
     *
     * @param  {number} a Value/Container to compare against b
     * @param  {number} b Value/Container to compare against a
     *
     * Throws an error if they are not equal
     */
    deepEqual: function(a, b, errorMessage){
        // Make sure they are the same container type first (Object or array)
        assert.equal(Array.isArray(a), Array.isArray(b), errorMessage);

        // object, number, or string work correctly just using typeof, compare that too
        assert.equal(typeof a, typeof b, errorMessage);

        // Now compare values
        const typeOfA = typeof a;
        if( typeOfA === 'number' ) {
            return epsilon.equal(a, b, errorMessage);
        } else if( typeOfA === 'string' ) {
            return a === b;
        }
        // [] or {}
        else if( typeOfA === 'object'){
            // They are arrays
            if( Array.isArray(a) ) {
                assert(a.length, b.length, errorMessage);

                let noMismatchFound = true;
                a.forEach( (_, index) => {
                    if( !epsilon.deepEqual(a[index], b[index], errorMessage) ){
                        noMismatchFound = false;
                    }
                })

                return noMismatchFound;
            }
            // They are objects
            else {
                const aKeys = Object.keys(a);
                const bKeys = Object.keys(b);

                // Objects must both have the same amount of keys
                assert.equal(aKeys.length, bKeys.length, errorMessage);

                let noMismatchFound = true;
                aKeys.forEach( keyName => {
                    // Make sure the key exists in B too
                    assert( typeof b[keyName] !== 'undefined', errorMessage);

                    if( !epsilon.deepEqual(a[keyName], b[keyName], errorMessage) ){
                        noMismatchFound = false;
                    }
                });
                return noMismatchFound;
            }
        }
    },
};

module.exports = epsilon;
